/* ══════════════════════════════════════════════════════════════
   ELEMENTAL CLUB — TICKET SYSTEM v5
   Modal: diseño renovado con header integrado + logo
   PDF: jsPDF vectorial con logo embebido + nuevo layout
   Sin cartera en comprobante de cliente
══════════════════════════════════════════════════════════════ */
(function () {
  'use strict';

  var ticketActivo = null;
  window._ultimoIngresoDatos = null;

  /* ── Logo en base64 (JPEG) ── */
  var LOGO_B64 = '';

  /* ── CSS ─────────────────────────────────────────────────── */
  var style = document.createElement('style');
  style.textContent = `
    .ticket-overlay {
      display:none; position:fixed; inset:0; z-index:1050;
      background:rgba(0,0,0,0.92); backdrop-filter:blur(20px);
      align-items:center; justify-content:center; padding:1rem; overflow-y:auto;
    }
    .ticket-overlay.on { display:flex; animation:tkovIn .28s cubic-bezier(.22,1,.36,1); }
    @keyframes tkovIn { from{opacity:0;transform:scale(.97)} to{opacity:1;transform:scale(1)} }

    .ticket-modal {
      background:#0e0e0e;
      border:1px solid rgba(255,77,0,.18);
      width:100%; max-width:420px;
      border-radius:12px; margin:auto; position:relative; overflow:hidden;
      box-shadow:0 40px 100px rgba(0,0,0,.8), 0 0 0 1px rgba(255,77,0,.08);
      animation:tkmUp .32s cubic-bezier(.22,1,.36,1);
    }
    @keyframes tkmUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:none} }

    /* ── Header naranja con logo ── */
    .tk-modal-head {
      background:linear-gradient(135deg, #FF4D00 0%, #CC3D00 100%);
      padding:1.1rem 1.25rem 0;
      position:relative;
    }
    .tk-modal-head-top {
      display:flex; align-items:center; justify-content:space-between; margin-bottom:.85rem;
    }
    .tk-brand-row {
      display:flex; align-items:center; gap:.65rem;
    }
    .tk-logo-box {
      width:38px; height:38px; background:rgba(255,255,255,0.92);
      border-radius:7px; overflow:hidden; flex-shrink:0;
      display:flex; align-items:center; justify-content:center;
    }
    .tk-logo-box img { width:100%; height:100%; object-fit:contain; }
    .tk-brand-text {}
    .tk-brand-name {
      font-family:'Bebas Neue',sans-serif; font-size:1.15rem; letter-spacing:.06em;
      color:#fff; line-height:1;
    }
    .tk-brand-sub {
      font-size:.52rem; color:rgba(255,255,255,.65); letter-spacing:.18em;
      text-transform:uppercase; margin-top:1px;
    }
    .tk-close-btn {
      width:30px; height:30px; border-radius:50%;
      background:rgba(255,255,255,.15); border:1px solid rgba(255,255,255,.25);
      display:flex; align-items:center; justify-content:center;
      cursor:pointer; color:rgba(255,255,255,.8); font-size:.78rem;
      transition:all .15s; flex-shrink:0; line-height:1;
    }
    .tk-close-btn:hover { background:rgba(0,0,0,.2); border-color:rgba(255,255,255,.4); }

    /* Banda ID dentro del header */
    .tk-id-band {
      background:rgba(0,0,0,.28);
      margin:0 -1.25rem;
      padding:.5rem 1.25rem;
      display:flex; align-items:center; justify-content:space-between;
    }
    .tk-id-lbl { font-size:.5rem; color:rgba(255,255,255,.5); letter-spacing:.18em; text-transform:uppercase; }
    .tk-id-val { font-family:'Bebas Neue',sans-serif; font-size:.95rem; color:#fff; letter-spacing:.05em; }

    /* ── Bloque cliente ── */
    .tk-client-block {
      padding:.85rem 1.25rem .7rem;
      border-bottom:1px solid rgba(255,255,255,.06);
      background:#111;
    }
    .tk-client-lbl {
      font-size:.5rem; font-weight:700; letter-spacing:.18em; text-transform:uppercase;
      color:rgba(255,255,255,.3); margin-bottom:.3rem;
    }
    .tk-client-name {
      font-family:'Bebas Neue',sans-serif; font-size:1.3rem; letter-spacing:.04em;
      color:#fff; line-height:1;
    }
    .tk-client-plan {
      font-size:.7rem; color:rgba(255,255,255,.4); margin-top:.25rem;
    }

    /* ── Filas de datos ── */
    .tk-rows { padding:.6rem 1.25rem; }
    .trow {
      display:flex; justify-content:space-between; align-items:center;
      padding:.42rem 0; border-bottom:1px solid rgba(255,255,255,.04);
    }
    .trow:last-child { border-bottom:none; }
    .trow-key {
      font-size:.56rem; font-weight:700; letter-spacing:.14em; text-transform:uppercase;
      color:rgba(255,255,255,.28); flex-shrink:0; padding-right:.75rem;
    }
    .trow-val { font-size:.78rem; font-weight:600; color:rgba(255,255,255,.8); text-align:right; }
    .trow-val.green { color:#4ade80; font-weight:700; }

    /* ── Bloque monto ── */
    .tk-amount-block {
      margin:.2rem 1.25rem .85rem;
      background:rgba(255,77,0,.08);
      border:1px solid rgba(255,77,0,.22);
      border-left:3px solid #FF4D00;
      border-radius:6px; padding:.7rem 1rem;
      display:flex; align-items:center; justify-content:space-between;
    }
    .tk-amount-lbl {
      font-size:.5rem; font-weight:700; letter-spacing:.14em; text-transform:uppercase;
      color:rgba(255,77,0,.7); margin-bottom:.2rem;
    }
    .tk-amount-val {
      font-family:'Bebas Neue',sans-serif; font-size:1.9rem; color:#FF4D00; line-height:1;
    }
    .tk-amount-empleado { text-align:right; }
    .tk-amount-empleado-lbl { font-size:.48rem; color:rgba(255,255,255,.25); letter-spacing:.1em; text-transform:uppercase; margin-bottom:.2rem; }
    .tk-amount-empleado-val { font-size:.72rem; font-weight:600; color:rgba(255,255,255,.45); }

    /* ── Footer ── */
    .tk-foot {
      background:rgba(255,77,0,.05); border-top:1px solid rgba(255,77,0,.1);
      padding:.55rem 1.25rem; text-align:center;
      font-size:.55rem; color:rgba(255,255,255,.2); letter-spacing:.04em; line-height:1.6;
    }

    /* ── Acciones ── */
    .tk-actions { padding:.1rem 1.25rem .9rem; display:flex; flex-direction:column; gap:.5rem; }
    .btn-dl-ticket {
      width:100%; padding:.82rem; background:#FF4D00; color:#fff;
      border:none; font-family:'DM Sans',sans-serif; font-size:.72rem;
      font-weight:800; letter-spacing:.16em; text-transform:uppercase;
      cursor:pointer; border-radius:6px;
      clip-path:polygon(7px 0%,100% 0%,calc(100% - 7px) 100%,0% 100%);
      transition:all .22s; display:flex; align-items:center; justify-content:center; gap:.5rem;
    }
    .btn-dl-ticket:hover { background:#CC3D00; transform:translateY(-2px); box-shadow:0 8px 24px rgba(255,77,0,.4); }
    .btn-dl-ticket:disabled { opacity:.4; cursor:not-allowed; transform:none; box-shadow:none; clip-path:none; }
    .btn-dl-ticket.success { background:#16a34a; clip-path:none; }
    .btn-dl-ticket.generating { background:#444; clip-path:none; }
    .ticket-cancel-btn {
      width:100%; padding:.65rem;
      background:transparent; border:1px solid rgba(255,255,255,.08);
      color:rgba(255,255,255,.3); font-family:'DM Sans',sans-serif;
      font-size:.68rem; font-weight:700; letter-spacing:.12em; text-transform:uppercase;
      cursor:pointer; border-radius:6px; transition:all .18s;
    }
    .ticket-cancel-btn:hover { border-color:rgba(255,255,255,.18); color:rgba(255,255,255,.55); }

    /* Botones en tabla de movimientos */
    .btn-mov-ticket, .btn-ticket-sm {
      background:transparent; border:1px solid rgba(255,77,0,.4); color:#FF4D00;
      padding:.25rem .65rem; font-size:.58rem; font-weight:800; letter-spacing:.1em;
      text-transform:uppercase; cursor:pointer; border-radius:3px; transition:all .18s;
      white-space:nowrap; font-family:'DM Sans',sans-serif;
    }
    .btn-mov-ticket { margin-left:.3rem; }
    .btn-mov-ticket:hover, .btn-ticket-sm:hover { background:rgba(255,77,0,.12); border-color:#FF4D00; }

    /* Toast de confirmación */
    .tk-toast {
      position:fixed; bottom:1.5rem; left:50%; transform:translateX(-50%) translateY(80px);
      background:#16a34a; color:#fff; padding:.6rem 1.2rem; border-radius:99px;
      font-family:'DM Sans',sans-serif; font-size:.72rem; font-weight:700;
      letter-spacing:.08em; z-index:2000; transition:transform .3s cubic-bezier(.22,1,.36,1);
      display:flex; align-items:center; gap:.5rem; white-space:nowrap;
      box-shadow:0 8px 24px rgba(0,0,0,.4);
    }
    .tk-toast.on { transform:translateX(-50%) translateY(0); }
  `;
  document.head.appendChild(style);

  /* ── Toast helper ── */
  var toastEl = null;
  function showToast(msg) {
    if (!toastEl) {
      toastEl = document.createElement('div');
      toastEl.className = 'tk-toast';
      document.body.appendChild(toastEl);
    }
    toastEl.innerHTML = '&#10003; ' + msg;
    toastEl.classList.add('on');
    setTimeout(function () { toastEl.classList.remove('on'); }, 3000);
  }

  /* ── HTML del modal ── */
  var wrapper = document.createElement('div');
  wrapper.innerHTML = `
    <div class="ticket-overlay" id="ticket-overlay">
      <div class="ticket-modal">
        <div class="tk-modal-head">
          <div class="tk-modal-head-top">
            <div class="tk-brand-row">
              <div class="tk-logo-box">
                <img src="data:image/jpeg;base64,${LOGO_B64}" alt="Elemental Club" />
              </div>
              <div class="tk-brand-text">
                <div class="tk-brand-name">ELEMENTAL CLUB</div>
                <div class="tk-brand-sub">Comprobante de pago</div>
              </div>
            </div>
            <div class="tk-close-btn" id="ticket-close-btn">&#10005;</div>
          </div>
          <div class="tk-id-band">
            <span class="tk-id-lbl">ID Operaci&#243;n</span>
            <span class="tk-id-val" id="ticket-op-id">—</span>
          </div>
        </div>

        <div class="tk-client-block">
          <div class="tk-client-lbl">Cliente</div>
          <div class="tk-client-name" id="ticket-cliente-nombre">—</div>
          <div class="tk-client-plan" id="ticket-cliente-plan">—</div>
        </div>

        <div class="tk-rows" id="ticket-rows-container"></div>

        <div class="tk-amount-block">
          <div>
            <div class="tk-amount-lbl">Total pagado</div>
            <div class="tk-amount-val" id="ticket-monto">$0.00</div>
          </div>
          <div class="tk-amount-empleado" id="ticket-empleado-block" style="display:none">
            <div class="tk-amount-empleado-lbl">Atendido por</div>
            <div class="tk-amount-empleado-val" id="ticket-empleado-val">—</div>
          </div>
        </div>

        <div class="tk-actions">
          <button class="btn-dl-ticket" id="btn-dl-ticket">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
              <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
              <polyline points="7 10 12 15 17 10"/>
              <line x1="12" y1="15" x2="12" y2="3"/>
            </svg>
            Descargar PDF
          </button>
          <button class="ticket-cancel-btn" id="ticket-cancel-btn">Cerrar</button>
        </div>

        <div class="tk-foot">Elemental Club &middot; Le&#243;n, Gto. &middot; 477 924 8796 &middot; recepcionelemental@hotmail.com</div>
      </div>
    </div>
  `;
  document.body.appendChild(wrapper);

  document.getElementById('ticket-overlay').addEventListener('click', function (e) { if (e.target === this) cerrarTicket(); });
  document.getElementById('ticket-close-btn').addEventListener('click', cerrarTicket);
  document.getElementById('ticket-cancel-btn').addEventListener('click', cerrarTicket);
  document.getElementById('btn-dl-ticket').addEventListener('click', descargarTicketPDF);

  /* ── Helpers ── */
  window.generarOperationId = function (fecha) {
    var d = fecha ? fecha.replace(/-/g, '') : new Date().toLocaleDateString('sv-SE', { timeZone: 'America/Mexico_City' }).replace(/-/g, '');
    var chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    var rand = '';
    for (var i = 0; i < 4; i++) rand += chars[Math.floor(Math.random() * chars.length)];
    return 'EC-' + d + '-' + rand + Date.now().toString(36).slice(-3).toUpperCase();
  };

  function fmtMXN(n) {
    return '$' + parseFloat(n || 0).toLocaleString('es-MX', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

  function fechaLarga(iso) {
    if (!iso) return '—';
    return new Date(iso + 'T12:00:00').toLocaleDateString('es-MX', {
      weekday: 'long', day: '2-digit', month: 'long', year: 'numeric'
    });
  }

  function mkTrow(key, val, cls) {
    return '<div class="trow"><span class="trow-key">' + key + '</span><span class="trow-val' + (cls ? ' ' + cls : '') + '">' + val + '</span></div>';
  }

  /* ── Abrir modal ── */
  window.abrirTicket = function (datos) {
    ticketActivo = datos;

    document.getElementById('ticket-op-id').textContent = datos.operationId || '—';
    document.getElementById('ticket-cliente-nombre').textContent = (datos.nombre || '—').toUpperCase();
    document.getElementById('ticket-cliente-plan').textContent = datos.plan || datos.categoria || '—';
    document.getElementById('ticket-monto').textContent = fmtMXN(datos.monto);

    var empleadoBlock = document.getElementById('ticket-empleado-block');
    if (datos.empleado) {
      document.getElementById('ticket-empleado-val').textContent = datos.empleado;
      empleadoBlock.style.display = 'block';
    } else {
      empleadoBlock.style.display = 'none';
    }

    var filas = '';
    filas += mkTrow('Fecha', fechaLarga(datos.fecha));
    if (datos.meses) filas += mkTrow('Duración', datos.meses + (parseInt(datos.meses) === 1 ? ' mes' : ' meses'));
    if (datos.expiracion) filas += mkTrow('Vence', datos.expiracion, 'green');
    document.getElementById('ticket-rows-container').innerHTML = filas;

    var btn = document.getElementById('btn-dl-ticket');
    btn.disabled = false;
    btn.className = 'btn-dl-ticket';
    btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Descargar PDF';

    document.getElementById('ticket-overlay').classList.add('on');
    document.body.style.overflow = 'hidden';
  };

  function cerrarTicket() {
    document.getElementById('ticket-overlay').classList.remove('on');
    document.body.style.overflow = '';
  }
  window.cerrarTicket = cerrarTicket;

  /* ════════════════════════════════════════════════════════
     PDF — jsPDF vectorial con logo embebido
  ════════════════════════════════════════════════════════ */
  function loadJsPDF() {
    return new Promise(function (resolve, reject) {
      if (window.jspdf && window.jspdf.jsPDF) { resolve(window.jspdf.jsPDF); return; }
      if (window.jsPDF) { resolve(window.jsPDF); return; }
      var sc = document.createElement('script');
      sc.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
      sc.onload = function () {
        var J = (window.jspdf && window.jspdf.jsPDF) || window.jsPDF;
        if (J) resolve(J); else reject(new Error('jsPDF no disponible'));
      };
      sc.onerror = function () { reject(new Error('No se pudo cargar jsPDF')); };
      document.head.appendChild(sc);
    });
  }

  function centeredText(doc, text, y, maxWidth) {
    var w = doc.getStringUnitWidth(text) * doc.getFontSize() / doc.internal.scaleFactor;
    doc.text(text, (maxWidth - w) / 2, y);
  }

  function descargarTicketPDF() {
    if (!ticketActivo) return;
    var d = ticketActivo;
    var btn = document.getElementById('btn-dl-ticket');
    btn.disabled = true;
    btn.className = 'btn-dl-ticket generating';
    btn.innerHTML = '&#8987; Generando…';

    loadJsPDF().then(function (jsPDF) {
      var W = 80, margin = 6, innerW = W - margin * 2;

      /* Colores */
      var OR    = [255, 77, 0];
      var OR2   = [204, 61, 0];
      var DARK  = [20, 20, 20];
      var GRAY  = [110, 110, 110];
      var LGRAY = [220, 220, 220];
      var GREEN_R = [22, 163, 74];
      var NEAR_WHITE = [252, 252, 252];
      var BLACK_BG  = [12, 12, 12];

      function buildPDF(doc) {
        var y = 0;

        /* ── 1. HEADER NARANJA ── */
        doc.setFillColor(OR[0], OR[1], OR[2]);
        doc.rect(0, 0, W, 22, 'F');
        doc.setFillColor(OR2[0], OR2[1], OR2[2]);
        doc.rect(0, 17, W, 5, 'F');

        /* Logo embebido (cuadrado blanco 14x14 en esquina izq) */
        doc.setFillColor(255, 255, 255);
        doc.roundedRect ? doc.roundedRect(margin, 4, 14, 14, 1.5, 1.5, 'F') : doc.rect(margin, 4, 14, 14, 'F');
        try {
          doc.addImage(LOGO_B64, 'JPEG', margin + 0.5, 4.5, 13, 13);
        } catch(e) { /* fallback silencioso si falla */ }

        /* Nombre del gym junto al logo */
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(13);
        doc.setTextColor(255, 255, 255);
        doc.text('ELEMENTAL CLUB', margin + 17, 10);
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(5.5);
        doc.setTextColor(255, 220, 200);
        doc.text('COMPROBANTE DE PAGO OFICIAL', margin + 17, 15);

        y = 22;

        /* ── 2. BANDA NEGRA — ID OPERACIÓN ── */
        doc.setFillColor(BLACK_BG[0], BLACK_BG[1], BLACK_BG[2]);
        doc.rect(0, y, W, 9, 'F');

        doc.setFont('helvetica', 'normal');
        doc.setFontSize(5);
        doc.setTextColor(120, 120, 120);
        doc.text('ID OPERACION', margin, y + 5.5);

        var idText = d.operationId || '—';
        doc.setFont('helvetica', 'bold');
        doc.setFontSize(7.5);
        doc.setTextColor(OR[0], OR[1], OR[2]);
        var idW = doc.getStringUnitWidth(idText) * 7.5 / doc.internal.scaleFactor;
        doc.text(idText, W - margin - idW, y + 5.5);

        y += 11;

        /* ── 3. BLOQUE CLIENTE ── */
        doc.setFillColor(NEAR_WHITE[0], NEAR_WHITE[1], NEAR_WHITE[2]);
        doc.rect(0, y, W, 16, 'F');

        doc.setFont('helvetica', 'normal');
        doc.setFontSize(5);
        doc.setTextColor(GRAY[0], GRAY[1], GRAY[2]);
        doc.text('CLIENTE', margin, y + 5);

        doc.setFont('helvetica', 'bold');
        doc.setFontSize(11);
        doc.setTextColor(DARK[0], DARK[1], DARK[2]);
        doc.text((d.nombre || 'Sin nombre').toUpperCase(), margin, y + 12, { maxWidth: innerW });

        var plan = d.plan || d.categoria || '';
        if (plan) {
          doc.setFont('helvetica', 'normal');
          doc.setFontSize(6);
          doc.setTextColor(GRAY[0], GRAY[1], GRAY[2]);
          /* plan abreviado al lado derecho */
          var plW = doc.getStringUnitWidth(plan) * 6 / doc.internal.scaleFactor;
          doc.text(plan, W - margin - plW, y + 12);
        }

        y += 18;

        /* ── 4. SEPARADOR ── */
        doc.setDrawColor(LGRAY[0], LGRAY[1], LGRAY[2]);
        doc.setLineWidth(0.25);
        doc.line(margin, y, W - margin, y);
        y += 4;

        /* ── 5. FUNCIÓN ROW ── */
        function row(label, value, valueColor, bold) {
          doc.setFont('helvetica', 'normal');
          doc.setFontSize(5);
          doc.setTextColor(GRAY[0], GRAY[1], GRAY[2]);
          doc.text(label.toUpperCase(), margin, y);

          doc.setFont('helvetica', bold ? 'bold' : 'normal');
          doc.setFontSize(7.5);
          if (valueColor) doc.setTextColor(valueColor[0], valueColor[1], valueColor[2]);
          else doc.setTextColor(DARK[0], DARK[1], DARK[2]);

          var valW = doc.getStringUnitWidth(value) * 7.5 / doc.internal.scaleFactor;
          var xVal = W - margin - valW;
          if (xVal < margin + 18) xVal = margin + 18;
          doc.text(value, xVal, y, { maxWidth: innerW - 20 });

          y += 6;
          doc.setDrawColor(235, 235, 235);
          doc.setLineWidth(0.15);
          doc.line(margin, y - 1.5, W - margin, y - 1.5);
        }

        /* ── 6. DATOS ── */
        var fechaStr = d.fecha
          ? new Date(d.fecha + 'T12:00:00').toLocaleDateString('es-MX', { day: '2-digit', month: 'short', year: 'numeric' })
          : '—';

        row('Fecha de pago', fechaStr);
        if (d.meses) row('Duracion', d.meses + (parseInt(d.meses) === 1 ? ' mes' : ' meses'));
        if (d.expiracion) row('Vigencia hasta', d.expiracion, GREEN_R, true);
        if (d.empleado) row('Atendido por', d.empleado);

        y += 3;

        /* ── 7. BLOQUE MONTO ── */
        doc.setFillColor(255, 248, 244);
        doc.rect(margin, y, innerW, 20, 'F');
        doc.setDrawColor(OR[0], OR[1], OR[2]);
        doc.setLineWidth(0.6);
        doc.line(margin, y, margin, y + 20);

        doc.setFont('helvetica', 'normal');
        doc.setFontSize(5);
        doc.setTextColor(OR[0], OR[1], OR[2]);
        doc.text('MONTO TOTAL PAGADO', margin + 3, y + 6);

        doc.setFont('helvetica', 'bold');
        doc.setFontSize(22);
        doc.setTextColor(OR[0], OR[1], OR[2]);
        doc.text(fmtMXN(d.monto), margin + 3, y + 16);

        y += 24;

        /* ── 8. LÍNEA PUNTEADA ── */
        doc.setDrawColor(LGRAY[0], LGRAY[1], LGRAY[2]);
        doc.setLineWidth(0.15);
        doc.setLineDashPattern([1, 1.5], 0);
        doc.line(margin, y, W - margin, y);
        doc.setLineDashPattern([], 0);
        y += 5;

        /* ── 9. FOOTER ── */
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(5);
        doc.setTextColor(GRAY[0], GRAY[1], GRAY[2]);
        [
          'Este comprobante es valido como recibo oficial.',
          'Elemental Club · Leon, Gto.',
          'Tel: 477 924 8796',
          'recepcionelemental@hotmail.com',
          'P. Magisterial 1519, Punta del Este'
        ].forEach(function (l) { centeredText(doc, l, y, W); y += 4; });
        y += 2;

        /* ── 10. BANDA NARANJA FINAL ── */
        doc.setFillColor(OR[0], OR[1], OR[2]);
        doc.rect(0, y, W, 4, 'F');
        y += 4;

        return y;
      }

      /* Medir altura con doc provisional */
      var docMeasure = new jsPDF({ orientation: 'portrait', unit: 'mm', format: [W, 300] });
      var measuredH = buildPDF(docMeasure) + 4;

      /* Generar doc final con altura exacta */
      var finalDoc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: [W, Math.max(measuredH, 120)] });
      buildPDF(finalDoc);

      var fileName = 'Ticket_EC_' + (d.operationId || 'SIN-ID').replace(/[^A-Z0-9\-]/gi, '_') + '.pdf';
      finalDoc.save(fileName);

      btn.disabled = false;
      btn.className = 'btn-dl-ticket success';
      btn.innerHTML = '&#10003; PDF descargado';
      showToast('Ticket guardado correctamente');

      setTimeout(function () {
        btn.className = 'btn-dl-ticket';
        btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Descargar PDF';
      }, 3500);

    }).catch(function (e) {
      btn.disabled = false;
      btn.className = 'btn-dl-ticket';
      btn.innerHTML = '&#9888; Error — reintentar';
      alert('Error al generar PDF: ' + e.message);
    });
  }
  window.descargarTicketPDF = descargarTicketPDF;

  /* ── Ticket desde tabla de movimientos ── */
  window.abrirTicketMov = function (id, tipo) {
    var movData = window.movData || [];
    var mov = movData.find(function (r) { return String(r.id) === String(id) && r.tipo === tipo; });
    if (mov) {
      window.abrirTicket({
        nombre: mov.concepto, plan: mov.categoria, categoria: mov.categoria,
        monto: mov.monto, fecha: mov.fecha, cartera: mov.cartera,
        meses: null, expiracion: null,
        operationId: mov.operation_id || window.generarOperationId(mov.fecha),
        empleado: mov.empleado,
      });
      return;
    }
    if (!window.supabase) { alert('Sin conexión.'); return; }
    window.supabase.from('ingresos')
      .select('id,nombre,monto,fecha,categoria,cartera,usuario,operation_id,descripcion')
      .eq('id', id).single()
      .then(function (r) {
        if (r.error || !r.data) { alert('Movimiento no encontrado.'); return; }
        var row = r.data;
        window.abrirTicket({
          nombre: row.nombre, plan: row.descripcion || row.categoria, categoria: row.categoria,
          monto: row.monto, fecha: row.fecha, cartera: row.cartera,
          meses: null, expiracion: null,
          operationId: row.operation_id || window.generarOperationId(row.fecha),
          empleado: row.usuario,
        });
      })
      .catch(function (e) { alert('Error: ' + e.message); });
  };

  console.log('✅ Elemental Club — Ticket System v5 (jsPDF + logo + nuevo diseño)');
})();